function maxANDSum(nums, numSlots) {
    let slot = new Array(numSlots + 1).fill(0);
    for (let num of nums) {
        for (let j = numSlots; j > 0; j--) {
            let newVal = num & j;
            if (newVal > slot[j]) slot[j] = newVal;
        }
    }

    return slot.reduce((acc, val) => acc + val, 0);
}
