public int maxANDSum(int[] nums, int numSlots) {
    int[] slot = new int[numSlots + 1];
    for (int num : nums) {
        for (int j = numSlots; j > 0; j--) {
            int newVal = num & j;
            if (newVal > slot[j]) slot[j] = newVal;
        }
    }

    int sum = 0;
    for (int s : slot) {
        sum += s;
    }
    return sum;
}
